from flask import Flask, request, jsonify
from web3 import Web3
import os
from functools import wraps
from datetime import datetime, timedelta
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Initialize Web3 with Ethereum node
ETH_NODE_URL = os.getenv('ETH_NODE_URL', 'https://mainnet.infura.io/v3/YOUR_PROJECT_ID')
w3 = Web3(Web3.HTTPProvider(ETH_NODE_URL))

# Whitelist of allowed domains (security measure)
ALLOWED_ORIGINS = os.getenv('ALLOWED_ORIGINS', '').split(',') if os.getenv('ALLOWED_ORIGINS') else ['localhost', '127.0.0.1']

# Rate limiting configuration
RATE_LIMIT_WINDOW = int(os.getenv('RATE_LIMIT_WINDOW', '300'))  # 5 minutes
MAX_REQUESTS_PER_WINDOW = int(os.getenv('MAX_REQUESTS_PER_WINDOW', '10'))

# Simple in-memory rate limiter (use Redis in production)
request_counts = {}

def validate_eth_address(address):
    """Validate Ethereum address format"""
    if not address or not isinstance(address, str):
        return False
    if not address.startswith('0x') or len(address) != 42:
        return False
    try:
        return w3.isAddress(address)
    except:
        return False

def validate_signature(signature):
    """Validate signature format"""
    if not signature or not isinstance(signature, str):
        return False
    if not signature.startswith('0x') or len(signature) != 132:
        return False
    return True

def rate_limit():
    """Simple rate limiting decorator"""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            client_ip = request.environ.get('HTTP_X_FORWARDED_FOR', request.remote_addr)
            now = datetime.utcnow()
            
            if client_ip not in request_counts:
                request_counts[client_ip] = []
            
            # Remove old requests
            request_counts[client_ip] = [
                req_time for req_time in request_counts[client_ip]
                if now - req_time < timedelta(seconds=RATE_LIMIT_WINDOW)
            ]
            
            if len(request_counts[client_ip]) >= MAX_REQUESTS_PER_WINDOW:
                logger.warning(f"Rate limit exceeded for IP: {client_ip}")
                return jsonify({'error': 'Rate limit exceeded'}), 429
            
            request_counts[client_ip].append(now)
            return f(*args, **kwargs)
        return decorated_function
    return decorator

def verify_signature(message, signature, address):
    """Verify Ethereum signature using web3.py"""
    try:
        # Recover address from signature
        recovered_address = w3.eth.account.recover_message(message, signature=signature)
        
        # Compare recovered address with provided address
        if recovered_address.lower() == address.lower():
            return True
        return False
    except Exception as e:
        logger.error(f"Signature verification failed: {str(e)}")
        return False

@app.route('/auth/verify', methods=['POST'])
@rate_limit()
def verify_wallet_signature():
    """Verify Ethereum wallet signature for authentication"""
    try:
        data = request.get_json()
        
        # Validate input
        if not data:
            return jsonify({'error': 'Invalid JSON data'}), 400
        
        message = data.get('message')
        signature = data.get('signature')
        address = data.get('address')
        
        # Validate required fields
        if not all([message, signature, address]):
            return jsonify({'error': 'Missing required fields: message, signature, address'}), 400
        
        # Validate address format
        if not validate_eth_address(address):
            return jsonify({'error': 'Invalid Ethereum address format'}), 400
        
        # Validate signature format
        if not validate_signature(signature):
            return jsonify({'error': 'Invalid signature format'}), 400
        
        # Validate message
        if not isinstance(message, str) or len(message) > 1000:
            return jsonify({'error': 'Invalid message'}), 400
        
        # Verify signature
        if verify_signature(message, signature, address):
            logger.info(f"Successful authentication for address: {address}")
            return jsonify({
                'success': True,
                'address': address,
                'timestamp': datetime.utcnow().isoformat()
            })
        else:
            logger.warning(f"Failed authentication attempt for address: {address}")
            return jsonify({'error': 'Invalid signature'}), 401
            
    except Exception as e:
        logger.error(f"Authentication error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

